+        int v;
+    }
+
+    static class A extends P implements IA {}
+    static class B extends P implements IB {}
+
+    public static void main(String[] args) {
+        A a = new A();
+        B b = new B();
+        for (int i = 0; i < 20000; i++) {
+            test(a, b, false, false);
+            test(a, b, false, true);
+            test(a, b, true, false);
